import 'dart:convert';
import 'package:flutter/foundation.dart';

enum PaymentMethod { creditCard, debitCard, applePay, googlePay, inAppPurchase }

enum PaymentStatus { pending, processing, completed, failed, refunded, cancelled }

enum TransactionType { purchase, subscription, refund, verification }

class PaymentAmount {
  final double amount;
  final String currency;

  const PaymentAmount({required this.amount, this.currency = 'USD'});

  Map<String, dynamic> toJson() => {'amount': amount, 'currency': currency};

  factory PaymentAmount.fromJson(Map<String, dynamic> json) {
    return PaymentAmount(
      amount: (json['amount'] as num).toDouble(),
      currency: json['currency'] as String? ?? 'USD',
    );
  }

  int get amountInCents => (amount * 100).round();
}

class PaymentRequest {
  final String idempotencyKey;
  final PaymentAmount amount;
  final PaymentMethod method;
  final TransactionType type;
  final String? tokenizedCard;
  final String? productId;
  final Map<String, dynamic>? metadata;
  final DateTime createdAt;

  PaymentRequest({
    required this.idempotencyKey,
    required this.amount,
    required this.method,
    this.type = TransactionType.purchase,
    this.tokenizedCard,
    this.productId,
    this.metadata,
  }) : createdAt = DateTime.now().toUtc();

  Map<String, dynamic> toJson() => {
    'idempotency_key': idempotencyKey,
    'amount': amount.toJson(),
    'method': method.name,
    'type': type.name,
    'tokenized_card': tokenizedCard,
    'product_id': productId,
    'metadata': metadata,
    'created_at': createdAt.toIso8601String(),
  };
}

class PaymentResult {
  final String transactionId;
  final PaymentStatus status;
  final PaymentAmount amount;
  final String? receiptData;
  final String? errorMessage;
  final String? errorCode;
  final DateTime processedAt;
  final Map<String, dynamic>? gatewayResponse;

  const PaymentResult({
    required this.transactionId,
    required this.status,
    required this.amount,
    this.receiptData,
    this.errorMessage,
    this.errorCode,
    required this.processedAt,
    this.gatewayResponse,
  });

  bool get isSuccessful => status == PaymentStatus.completed;

  factory PaymentResult.fromJson(Map<String, dynamic> json) {
    return PaymentResult(
      transactionId: json['transaction_id'] as String,
      status: PaymentStatus.values.firstWhere(
        (e) => e.name == json['status'],
        orElse: () => PaymentStatus.failed,
      ),
      amount: PaymentAmount.fromJson(json['amount'] as Map<String, dynamic>),
      receiptData: json['receipt_data'] as String?,
      errorMessage: json['error_message'] as String?,
      errorCode: json['error_code'] as String?,
      processedAt: DateTime.parse(json['processed_at'] as String),
      gatewayResponse: json['gateway_response'] as Map<String, dynamic>?,
    );
  }

  Map<String, dynamic> toJson() => {
    'transaction_id': transactionId,
    'status': status.name,
    'amount': amount.toJson(),
    'receipt_data': receiptData,
    'error_message': errorMessage,
    'error_code': errorCode,
    'processed_at': processedAt.toIso8601String(),
    'gateway_response': gatewayResponse,
  };
}

class InAppProduct {
  final String productId;
  final String title;
  final String description;
  final PaymentAmount price;
  final bool isSubscription;
  final String? subscriptionPeriod;

  const InAppProduct({
    required this.productId,
    required this.title,
    required this.description,
    required this.price,
    this.isSubscription = false,
    this.subscriptionPeriod,
  });
}

