import 'dart:convert';
import 'dart:math';
import 'dart:typed_data';
import 'package:crypto/crypto.dart';
import 'package:encrypt/encrypt.dart' as encrypt_lib;
import 'package:flutter_secure_storage/flutter_secure_storage.dart';
import 'package:uuid/uuid.dart';

class PaymentSecurity {
  static const _secureStorage = FlutterSecureStorage(
    aOptions: AndroidOptions(encryptedSharedPreferences: true),
    iOptions: IOSOptions(
      accessibility: KeychainAccessibility.first_unlock_this_device,
    ),
  );

  static const _encryptionKeyAlias = 'payment_encryption_key';
  static const _hmacKeyAlias = 'payment_hmac_key';

  static final PaymentSecurity _instance = PaymentSecurity._internal();
  factory PaymentSecurity() => _instance;
  PaymentSecurity._internal();

  encrypt_lib.Key? _encryptionKey;
  List<int>? _hmacKey;

  Future<void> initialize() async {
    await _ensureEncryptionKey();
    await _ensureHmacKey();
  }

  Future<void> _ensureEncryptionKey() async {
    String? storedKey = await _secureStorage.read(key: _encryptionKeyAlias);
    if (storedKey == null) {
      final key = encrypt_lib.Key.fromSecureRandom(32);
      await _secureStorage.write(
        key: _encryptionKeyAlias,
        value: base64Encode(key.bytes),
      );
      _encryptionKey = key;
    } else {
      _encryptionKey = encrypt_lib.Key(base64Decode(storedKey));
    }
  }

  Future<void> _ensureHmacKey() async {
    String? storedKey = await _secureStorage.read(key: _hmacKeyAlias);
    if (storedKey == null) {
      final random = Random.secure();
      final key = List<int>.generate(32, (_) => random.nextInt(256));
      await _secureStorage.write(
        key: _hmacKeyAlias,
        value: base64Encode(key),
      );
      _hmacKey = key;
    } else {
      _hmacKey = base64Decode(storedKey);
    }
  }

  String encryptSensitiveData(String plaintext) {
    if (_encryptionKey == null) {
      throw StateError('PaymentSecurity not initialized');
    }
    final iv = encrypt_lib.IV.fromSecureRandom(16);
    final encrypter = encrypt_lib.Encrypter(
      encrypt_lib.AES(_encryptionKey!, mode: encrypt_lib.AESMode.cbc),
    );
    final encrypted = encrypter.encrypt(plaintext, iv: iv);
    // Prepend IV to ciphertext
    final combined = base64Encode(iv.bytes + encrypted.bytes);
    return combined;
  }

  String decryptSensitiveData(String ciphertext) {
    if (_encryptionKey == null) {
      throw StateError('PaymentSecurity not initialized');
    }
    final decoded = base64Decode(ciphertext);
    final iv = encrypt_lib.IV(Uint8List.fromList(decoded.sublist(0, 16)));
    final encryptedBytes = decoded.sublist(16);
    final encrypter = encrypt_lib.Encrypter(
      encrypt_lib.AES(_encryptionKey!, mode: encrypt_lib.AESMode.cbc),
    );
    return encrypter.decrypt(
      encrypt_lib.Encrypted(Uint8List.fromList(encryptedBytes)),
      iv: iv,
    );
  }

  String generateHmac(String data) {
    if (_hmacKey == null) {
      throw StateError('PaymentSecurity not initialized');
    }
    final hmacSha256 = Hmac(sha256, _hmacKey!);
    final digest = hmacSha256.convert(utf8.encode(data));
    return digest.toString();
  }

  bool verifyHmac(String data, String expectedHmac) {
    final computedHmac = generateHmac(data);
    // Constant-time comparison to prevent timing attacks
    if (computedHmac.length != expectedHmac.length) return false;
    int result = 0;
    for (int i = 0; i < computedHmac.length; i++) {
      result |= computedHmac.codeUnitAt(i) ^ expectedHmac.codeUnitAt(i);
    }
    return result == 0;
  }

  String generateIdempotencyKey() {
    return const Uuid().v4();
  }

  String generateTransactionId() {
    final timestamp = DateTime.now().toUtc().millisecondsSinceEpoch;
    final random = const Uuid().v4().replaceAll('-', '').substring(0, 12);
    return 'txn_${timestamp}_$random';
  }

  /// Tokenize card number - never store raw card data
  String tokenizeCardNumber(String cardNumber) {
    final sanitized = cardNumber.replaceAll(RegExp(r'\s+'), '');
    if (!_isValidLuhn(sanitized)) {
      throw ArgumentError('Invalid card number');
    }
    final masked =
        '${'*' * (sanitized.length - 4)}${sanitized.substring(sanitized.length - 4)}';
    final token = encryptSensitiveData(sanitized);
    // Return only the token, never the raw number
    return token;
  }

  String maskCardNumber(String cardNumber) {
    final sanitized = cardNumber.replaceAll(RegExp(r'\s+'), '');
    if (sanitized.length < 4) return '****';
    return '**** **** **** ${sanitized.substring(sanitized.length - 4)}';
  }

  bool _isValidLuhn(String number) {
    int sum = 0;
    bool alternate = false;
    for (int i = number.length - 1; i >= 0; i--) {
      int digit = int.parse(number[i]);
      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      alternate = !alternate;
    }
    return sum % 10 == 0;
  }

  Future<void> storeToken(String key, String token) async {
    await _secureStorage.write(key: 'token_$key', value: token);
  }

  Future<String?> retrieveToken(String key) async {
    return await _secureStorage.read(key: 'token_$key');
  }

  Future<void> deleteToken(String key) async {
    await _secureStorage.delete(key: 'token_$key');
  }

  Future<void> clearAllTokens() async {
    await _secureStorage.deleteAll();
    _encryptionKey = null;
    _hmacKey = null;
  }
}

