import 'dart:collection';

class FraudDetector {
  static final FraudDetector _instance = FraudDetector._internal();
  factory FraudDetector() => _instance;
  FraudDetector._internal();

  final Queue<DateTime> _recentTransactions = Queue();
  static const int _maxTransactionsPerMinute = 5;
  static const int _maxTransactionsPerHour = 20;
  static const double _maxSingleTransactionAmount = 10000.0;
  static const double _maxDailyAmount = 50000.0;

  double _dailyTotal = 0.0;
  DateTime _dailyResetDate = DateTime.now().toUtc();

  FraudCheckResult checkTransaction({
    required double amount,
    required String currency,
    String? userId,
    String? deviceId,
  }) {
    _resetDailyIfNeeded();

    // Check single transaction limit
    if (amount > _maxSingleTransactionAmount) {
      return FraudCheckResult(
        isAllowed: false,
        reason: 'Transaction amount exceeds maximum limit',
        riskScore: 1.0,
      );
    }

    // Check negative or zero amount
    if (amount <= 0) {
      return FraudCheckResult(
        isAllowed: false,
        reason: 'Invalid transaction amount',
        riskScore: 1.0,
      );
    }

    // Check daily limit
    if (_dailyTotal + amount > _maxDailyAmount) {
      return FraudCheckResult(
        isAllowed: false,
        reason: 'Daily transaction limit exceeded',
        riskScore: 0.9,
      );
    }

    // Check rate limiting
    final now = DateTime.now().toUtc();
    _recentTransactions.removeWhere(
      (t) => now.difference(t).inMinutes > 60,
    );

    final transactionsLastMinute =
        _recentTransactions
            .where((t) => now.difference(t).inSeconds < 60)
            .length;

    if (transactionsLastMinute >= _maxTransactionsPerMinute) {
      return FraudCheckResult(
        isAllowed: false,
        reason: 'Too many transactions per minute',
        riskScore: 0.85,
      );
    }

    if (_recentTransactions.length >= _maxTransactionsPerHour) {
      return FraudCheckResult(
        isAllowed: false,
        reason: 'Too many transactions per hour',
        riskScore: 0.8,
      );
    }

    // Calculate risk score
    double riskScore = 0.0;
    if (amount > 5000) riskScore += 0.3;
    if (amount > 1000) riskScore += 0.1;
    if (transactionsLastMinute > 2) riskScore += 0.2;

    return FraudCheckResult(
      isAllowed: true,
      reason: null,
      riskScore: riskScore.clamp(0.0, 1.0),
    );
  }

  void recordTransaction(double amount) {
    _recentTransactions.add(DateTime.now().toUtc());
    _dailyTotal += amount;
  }

  void _resetDailyIfNeeded() {
    final now = DateTime.now().toUtc();
    if (now.day != _dailyResetDate.day ||
        now.month != _dailyResetDate.month ||
        now.year != _dailyResetDate.year) {
      _dailyTotal = 0.0;
      _dailyResetDate = now;
    }
  }
}

class FraudCheckResult {
  final bool isAllowed;
  final String? reason;
  final double riskScore;

  const FraudCheckResult({
    required this.isAllowed,
    this.reason,
    required this.riskScore,
  });
}

