import 'dart:convert';
import 'package:http/http.dart' as http;
import '../models/payment_models.dart';
import '../security/payment_security.dart';
import '../security/certificate_pinner.dart';
import 'payment_gateway.dart';

class StripeGateway implements PaymentGateway {
  final String _apiBaseUrl;
  final PaymentSecurity _security;
  final http.Client _httpClient;
  final String _publishableKey;

  StripeGateway({
    required String publishableKey,
    required String apiBaseUrl,
    PaymentSecurity? security,
  })  : _publishableKey = publishableKey,
        _apiBaseUrl = apiBaseUrl,
        _security = security ?? PaymentSecurity(),
        _httpClient = CertificatePinner.createSecureClient();

  Map<String, String> get _headers => {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer $_publishableKey',
    'Stripe-Version': '2023-10-16',
  };

  @override
  Future<PaymentResult> processPayment(PaymentRequest request) async {
    try {
      final hmac = _security.generateHmac(jsonEncode(request.toJson()));

      final response = await _httpClient
          .post(
            Uri.parse('$_apiBaseUrl/v1/payment_intents'),
            headers: {..._headers, 'X-Request-Signature': hmac},
            body: jsonEncode({
              'amount': request.amount.amountInCents,
              'currency': request.amount.currency.toLowerCase(),
              'payment_method': request.tokenizedCard,
              'confirm': true,
              'idempotency_key': request.idempotencyKey,
              'metadata': request.metadata ?? {},
            }),
          )
          .timeout(const Duration(seconds: 30));

      if (response.statusCode == 200 || response.statusCode == 201) {
        final data = jsonDecode(response.body) as Map<String, dynamic>;
        return PaymentResult(
          transactionId: data['id'] as String,
          status: _mapStripeStatus(data['status'] as String),
          amount: request.amount,
          receiptData: data['latest_charge']?['receipt_url'] as String?,
          processedAt: DateTime.now().toUtc(),
          gatewayResponse: data,
        );
      } else {
        final error = jsonDecode(response.body);
        return PaymentResult(
          transactionId: _security.generateTransactionId(),
          status: PaymentStatus.failed,
          amount: request.amount,
          errorMessage: error['error']?['message'] as String? ?? 'Payment failed',
          errorCode: error['error']?['code'] as String?,
          processedAt: DateTime.now().toUtc(),
        );
      }
    } catch (e) {
      return PaymentResult(
        transactionId: _security.generateTransactionId(),
        status: PaymentStatus.failed,
        amount: request.amount,
        errorMessage: 'Payment processing error: ${_sanitizeError(e.toString())}',
        errorCode: 'NETWORK_ERROR',
        processedAt: DateTime.now().toUtc(),
      );
    }
  }

  @override
  Future<PaymentResult> refundPayment(
    String transactionId,
    PaymentAmount amount,
  ) async {
    try {
      final response = await _httpClient
          .post(
            Uri.parse('$_apiBaseUrl/v1/refunds'),
            headers: _headers,
            body: jsonEncode({
              'payment_intent': transactionId,
              'amount': amount.amountInCents,
            }),
          )
          .timeout(const Duration(seconds: 30));

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body) as Map<String, dynamic>;
        return PaymentResult(
          transactionId: data['id'] as String,
          status: PaymentStatus.refunded,
          amount: amount,
          processedAt: DateTime.now().toUtc(),
          gatewayResponse: data,
        );
      } else {
        return PaymentResult(
          transactionId: transactionId,
          status: PaymentStatus.failed,
          amount: amount,
          errorMessage: 'Refund failed',
          processedAt: DateTime.now().toUtc(),
        );
      }
    } catch (e) {
      return PaymentResult(
        transactionId: transactionId,
        status: PaymentStatus.failed,
        amount: amount,
        errorMessage: 'Refund processing error',
        processedAt: DateTime.now().toUtc(),
      );
    }
  }

  @override
  Future<PaymentResult> verifyPayment(String transactionId) async {
    try {
      final response = await _httpClient
          .get(
            Uri.parse('$_apiBaseUrl/v1/payment_intents/$transactionId'),
            headers: _headers,
          )
          .timeout(const Duration(seconds: 15));

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body) as Map<String, dynamic>;
        return PaymentResult(
          transactionId: transactionId,
          status: _mapStripeStatus(data['status'] as String),
          amount: PaymentAmount(
            amount: (data['amount'] as int) / 100.0,
            currency: (data['currency'] as String).toUpperCase(),
          ),
          processedAt: DateTime.now().toUtc(),
          gatewayResponse: data,
        );
      } else {
        return PaymentResult(
          transactionId: transactionId,
          status: PaymentStatus.failed,
          amount: const PaymentAmount(amount: 0),
          errorMessage: 'Verification failed',
          processedAt: DateTime.now().toUtc(),
        );
      }
    } catch (e) {
      return PaymentResult(
        transactionId: transactionId,
        status: PaymentStatus.failed,
        amount: const PaymentAmount(amount: 0),
        errorMessage: 'Verification error',
        processedAt: DateTime.now().toUtc(),
      );
    }
  }

  @override
  Future<bool> isAvailable() async {
    try {
      final response = await _httpClient
          .get(Uri.parse('$_apiBaseUrl/v1/health'), headers: _headers)
          .timeout(const Duration(seconds: 5));
      return response.statusCode == 200;
    } catch (_) {
      return false;
    }
  }

  PaymentStatus _mapStripeStatus(String stripeStatus) {
    switch (stripeStatus) {
      case 'succeeded':
        return PaymentStatus.completed;
      case 'processing':
        return PaymentStatus.processing;
      case 'requires_payment_method':
      case 'requires_confirmation':
      case 'requires_action':
        return PaymentStatus.pending;
      case 'canceled':
        return PaymentStatus.cancelled;
      default:
        return PaymentStatus.failed;
    }
  }

  String _sanitizeError(String error) {
    // Remove any sensitive data from error messages
    return error
        .replaceAll(RegExp(r'sk_[a-zA-Z0-9]+'), '[REDACTED]')
        .replaceAll(RegExp(r'pk_[a-zA-Z0-9]+'), '[REDACTED]')
        .replaceAll(RegExp(r'\d{13,19}'), '[REDACTED]');
  }
}

