import 'dart:async';
import 'dart:io';
import 'package:in_app_purchase/in_app_purchase.dart';
import 'package:in_app_purchase_storekit/in_app_purchase_storekit.dart';
import 'package:in_app_purchase_android/in_app_purchase_android.dart';
import '../models/payment_models.dart';
import '../security/payment_security.dart';
import 'payment_gateway.dart';

class InAppPurchaseGateway implements PaymentGateway {
  final InAppPurchase _iap = InAppPurchase.instance;
  final PaymentSecurity _security;
  StreamSubscription<List<PurchaseDetails>>? _subscription;
  final Map<String, Completer<PaymentResult>> _pendingPurchases = {};

  InAppPurchaseGateway({PaymentSecurity? security})
      : _security = security ?? PaymentSecurity();

  Future<void> initialize() async {
    final available = await _iap.isAvailable();
    if (!available) {
      throw StateError('In-app purchases not available');
    }

    _subscription = _iap.purchaseStream.listen(
      _handlePurchaseUpdates,
      onError: _handlePurchaseError,
      onDone: () => _subscription?.cancel(),
    );
  }

  void _handlePurchaseUpdates(List<PurchaseDetails> purchases) {
    for (final purchase in purchases) {
      _processPurchaseUpdate(purchase);
    }
  }

  Future<void> _processPurchaseUpdate(PurchaseDetails purchase) async {
    final completer = _pendingPurchases[purchase.productID];

    switch (purchase.status) {
      case PurchaseStatus.purchased:
      case PurchaseStatus.restored:
        // Verify receipt server-side before completing
        final verified = await _verifyReceipt(purchase);
        if (verified) {
          await _iap.completePurchase(purchase);
          completer?.complete(PaymentResult(
            transactionId: purchase.purchaseID ?? _security.generateTransactionId(),
            status: PaymentStatus.completed,
            amount: const PaymentAmount(amount: 0), // Amount from store
            receiptData: _getReceiptData(purchase),
            processedAt: DateTime.now().toUtc(),
          ));
        } else {
          completer?.complete(PaymentResult(
            transactionId: purchase.purchaseID ?? _security.generateTransactionId(),
            status: PaymentStatus.failed,
            amount: const PaymentAmount(amount: 0),
            errorMessage: 'Receipt verification failed',
            processedAt: DateTime.now().toUtc(),
          ));
        }
        break;

      case PurchaseStatus.error:
        completer?.complete(PaymentResult(
          transactionId: _security.generateTransactionId(),
          status: PaymentStatus.failed,
          amount: const PaymentAmount(amount: 0),
          errorMessage: purchase.error?.message ?? 'Purchase failed',
          errorCode: purchase.error?.code,
          processedAt: DateTime.now().toUtc(),
        ));
        break;

      case PurchaseStatus.pending:
        // Still processing
        break;

      case PurchaseStatus.canceled:
        completer?.complete(PaymentResult(
          transactionId: _security.generateTransactionId(),
          status: PaymentStatus.cancelled,
          amount: const PaymentAmount(amount: 0),
          errorMessage: 'Purchase cancelled by user',
          processedAt: DateTime.now().toUtc(),
        ));
        break;
    }

    if (purchase.status != PurchaseStatus.pending) {
      _pendingPurchases.remove(purchase.productID);
    }
  }

  void _handlePurchaseError(dynamic error) {
    for (final completer in _pendingPurchases.values) {
      if (!completer.isCompleted) {
        completer.complete(PaymentResult(
          transactionId: _security.generateTransactionId(),
          status: PaymentStatus.failed,
          amount: const PaymentAmount(amount: 0),
          errorMessage: 'Purchase stream error',
          processedAt: DateTime.now().toUtc(),
        ));
      }
    }
    _pendingPurchases.clear();
  }

  @override
  Future<PaymentResult> processPayment(PaymentRequest request) async {
    if (request.productId == null) {
      return PaymentResult(
        transactionId: _security.generateTransactionId(),
        status: PaymentStatus.failed,
        amount: request.amount,
        errorMessage: 'Product ID is required for in-app purchases',
        processedAt: DateTime.now().toUtc(),
      );
    }

    try {
      final productDetails = await _getProductDetails(request.productId!);
      if (productDetails == null) {
        return PaymentResult(
          transactionId: _security.generateTransactionId(),
          status: PaymentStatus.failed,
          amount: request.amount,
          errorMessage: 'Product not found',
          processedAt: DateTime.now().toUtc(),
        );
      }

      final completer = Completer<PaymentResult>();
      _pendingPurchases[request.productId!] = completer;

      final purchaseParam = PurchaseParam(productDetails: productDetails);

      final initiated = await _iap.buyNonConsumable(
        purchaseParam: purchaseParam,
      );

      if (!initiated) {
        _pendingPurchases.remove(request.productId);
        return PaymentResult(
          transactionId: _security.generateTransactionId(),
          status: PaymentStatus.failed,
          amount: request.amount,
          errorMessage: 'Failed to initiate purchase',
          processedAt: DateTime.now().toUtc(),
        );
      }

      return completer.future.timeout(
        const Duration(minutes: 5),
        onTimeout: () {
          _pendingPurchases.remove(request.productId);
          return PaymentResult(
            transactionId: _security.generateTransactionId(),
            status: PaymentStatus.failed,
            amount: request.amount,
            errorMessage: 'Purchase timed out',
            processedAt: DateTime.now().toUtc(),
          );
        },
      );
    } catch (e) {
      _pendingPurchases.remove(request.productId);
      return PaymentResult(
        transactionId: _security.generateTransactionId(),
        status: PaymentStatus.failed,
        amount: request.amount,
        errorMessage: 'Purchase error: ${e.toString()}',
        processedAt: DateTime.now().toUtc(),
      );
    }
  }

  Future<ProductDetails?> _getProductDetails(String productId) async {
    final response = await _iap.queryProductDetails({productId});
    if (response.productDetails.isEmpty) return null;
    return response.productDetails.first;
  }

  Future<List<InAppProduct>> getAvailableProducts(Set<String> productIds) async {
    final response = await _iap.queryProductDetails(productIds);
    return response.productDetails.map((pd) {
      return InAppProduct(
        productId: pd.id,
        title: pd.title,
        description: pd.description,
        price: PaymentAmount(
          amount: pd.rawPrice,
          currency: pd.currencyCode,
        ),
      );
    }).toList();
  }

  Future<bool> _verifyReceipt(PurchaseDetails purchase) async {
    // Server-side receipt verification
    // This should call your backend which then verifies with Apple/Google
    final receiptData = _getReceiptData(purchase);
    if (receiptData == null) return false;

    // TODO: Implement server-side verification call
    // For now, return true - in production, ALWAYS verify server-side
    return true;
  }

  String? _getReceiptData(PurchaseDetails purchase) {
    if (Platform.isIOS) {
      final appStoreDetails =
          purchase as AppStorePurchaseDetails?;
      return appStoreDetails?.verificationData.serverVerificationData;
    } else if (Platform.isAndroid) {
      final googleDetails =
          purchase as GooglePlayPurchaseDetails?;
      return googleDetails?.verificationData.serverVerificationData;
    }
    return null;
  }

  @override
  Future<PaymentResult> refundPayment(
    String transactionId,
    PaymentAmount amount,
  ) async {
    // Refunds for IAP must be handled through Apple/Google
    return PaymentResult(
      transactionId: transactionId,
      status: PaymentStatus.failed,
      amount: amount,
      errorMessage: 'Refunds must be processed through the app store',
      processedAt: DateTime.now().toUtc(),
    );
  }

  @override
  Future<PaymentResult> verifyPayment(String transactionId) async {
    // Verify through server-side receipt validation
    return PaymentResult(
      transactionId: transactionId,
      status: PaymentStatus.pending,
      amount: const PaymentAmount(amount: 0),
      processedAt: DateTime.now().toUtc(),
    );
  }

  @override
  Future<bool> isAvailable() => _iap.isAvailable();

  Future<void> restorePurchases() async {
    await _iap.restorePurchases();
  }

  void dispose() {
    _subscription?.cancel();
    for (final completer in _pendingPurchases.values) {
      if (!completer.isCompleted) {
        completer.complete(PaymentResult(
          transactionId: _security.generateTransactionId(),
          status: PaymentStatus.cancelled,
          amount: const PaymentAmount(amount: 0),
          errorMessage: 'Gateway disposed',
          processedAt: DateTime.now().toUtc(),
        ));
      }
    }
    _pendingPurchases.clear();
  }
}

