import 'dart:io';
import 'package:pay/pay.dart';
import '../models/payment_models.dart';
import '../security/payment_security.dart';
import 'payment_gateway.dart';

class MobileWalletGateway implements PaymentGateway {
  final PaymentSecurity _security;
  final String _merchantId;
  final String _merchantName;
  final String _stripePublishableKey;

  MobileWalletGateway({
    required String merchantId,
    required String merchantName,
    required String stripePublishableKey,
    PaymentSecurity? security,
  })  : _merchantId = merchantId,
        _merchantName = merchantName,
        _stripePublishableKey = stripePublishableKey,
        _security = security ?? PaymentSecurity();

  List<PaymentItem> _buildPaymentItems(PaymentRequest request) {
    return [
      PaymentItem(
        label: 'Total',
        amount: request.amount.amount.toStringAsFixed(2),
        status: PaymentItemStatus.final_price,
      ),
    ];
  }

  Pay _createPayClient() {
    if (Platform.isIOS) {
      return Pay({
        PayProvider.apple_pay: PaymentConfiguration.fromJsonString('''
        {
          "provider": "apple_pay",
          "data": {
            "merchantIdentifier": "$_merchantId",
            "displayName": "$_merchantName",
            "merchantCapabilities": ["3DS", "debit", "credit"],
            "supportedNetworks": ["amex", "visa", "discover", "masterCard"],
            "countryCode": "US",
            "currencyCode": "USD"
          }
        }
        '''),
      });
    } else {
      return Pay({
        PayProvider.google_pay: PaymentConfiguration.fromJsonString('''
        {
          "provider": "google_pay",
          "data": {
            "environment": "PRODUCTION",
            "apiVersion": 2,
            "apiVersionMinor": 0,
            "allowedPaymentMethods": [{
              "type": "CARD",
              "parameters": {
                "allowedAuthMethods": ["PAN_ONLY", "CRYPTOGRAM_3DS"],
                "allowedCardNetworks": ["AMEX", "DISCOVER", "MASTERCARD", "VISA"]
              },
              "tokenizationSpecification": {
                "type": "PAYMENT_GATEWAY",
                "parameters": {
                  "gateway": "stripe",
                  "stripe:version": "2023-10-16",
                  "stripe:publishableKey": "$_stripePublishableKey"
                }
              }
            }],
            "merchantInfo": {
              "merchantId": "$_merchantId",
              "merchantName": "$_merchantName"
            },
            "transactionInfo": {
              "totalPriceStatus": "FINAL",
              "countryCode": "US",
              "currencyCode": "USD"
            }
          }
        }
        '''),
      });
    }
  }

  @override
  Future<PaymentResult> processPayment(PaymentRequest request) async {
    try {
      final payClient = _createPayClient();
      final provider =
          Platform.isIOS ? PayProvider.apple_pay : PayProvider.google_pay;

      final result = await payClient.showPaymentSelector(
        provider,
        _buildPaymentItems(request),
      );

      // The token from Apple Pay / Google Pay should be sent to your
      // payment processor (e.g., Stripe) server-side
      final token = result['token'] ?? result['paymentMethodData']?['token'];

      if (token != null) {
        return PaymentResult(
          transactionId: _security.generateTransactionId(),
          status: PaymentStatus.completed,
          amount: request.amount,
          receiptData: token.toString(),
          processedAt: DateTime.now().toUtc(),
          gatewayResponse: result,
        );
      } else {
        return PaymentResult(
          transactionId: _security.generateTransactionId(),
          status: PaymentStatus.failed,
          amount: request.amount,
          errorMessage: 'No payment token received',
          processedAt: DateTime.now().toUtc(),
        );
      }
    } catch (e) {
      return PaymentResult(
        transactionId: _security.generateTransactionId(),
        status: PaymentStatus.failed,
        amount: request.amount,
        errorMessage: 'Wallet payment failed: ${e.toString()}',
        processedAt: DateTime.now().toUtc(),
      );
    }
  }

  @override
  Future<PaymentResult> refundPayment(
    String transactionId,
    PaymentAmount amount,
  ) async {
    return PaymentResult(
      transactionId: transactionId,
      status: PaymentStatus.failed,
      amount: amount,
      errorMessage: 'Refunds must be processed through the payment gateway',
      processedAt: DateTime.now().toUtc(),
    );
  }

  @override
  Future<PaymentResult> verifyPayment(String transactionId) async {
    return PaymentResult(
      transactionId: transactionId,
      status: PaymentStatus.pending,
      amount: const PaymentAmount(amount: 0),
      processedAt: DateTime.now().toUtc(),
    );
  }

  @override
  Future<bool> isAvailable() async {
    try {
      final payClient = _createPayClient();
      final provider =
          Platform.isIOS ? PayProvider.apple_pay : PayProvider.google_pay;
      return await payClient.userCanPay(provider);
    } catch (_) {
      return false;
    }
  }
}

