import 'dart:async';
import 'package:flutter/foundation.dart';
import '../models/payment_models.dart';
import '../gateways/payment_gateway.dart';
import '../gateways/stripe_gateway.dart';
import '../gateways/in_app_purchase_gateway.dart';
import '../gateways/mobile_wallet_gateway.dart';
import '../security/payment_security.dart';
import '../security/fraud_detector.dart';
import 'transaction_logger.dart';

class PaymentService {
  final PaymentSecurity _security;
  final FraudDetector _fraudDetector;
  final TransactionLogger _logger;
  final Map<PaymentMethod, PaymentGateway> _gateways = {};

  bool _initialized = false;

  PaymentService({
    PaymentSecurity? security,
    FraudDetector? fraudDetector,
    TransactionLogger? logger,
  })  : _security = security ?? PaymentSecurity(),
        _fraudDetector = fraudDetector ?? FraudDetector(),
        _logger = logger ?? TransactionLogger();

  Future<void> initialize({
    required String stripePublishableKey,
    required String stripeApiBaseUrl,
    required String merchantId,
    required String merchantName,
  }) async {
    if (_initialized) return;

    await _security.initialize();

    // Register gateways
    _gateways[PaymentMethod.creditCard] = StripeGateway(
      publishableKey: stripePublishableKey,
      apiBaseUrl: stripeApiBaseUrl,
      security: _security,
    );

    _gateways[PaymentMethod.debitCard] = StripeGateway(
      publishableKey: stripePublishableKey,
      apiBaseUrl: stripeApiBaseUrl,
      security: _security,
    );

    final iapGateway = InAppPurchaseGateway(security: _security);
    await iapGateway.initialize();
    _gateways[PaymentMethod.inAppPurchase] = iapGateway;

    final walletGateway = MobileWalletGateway(
      merchantId: merchantId,
      merchantName: merchantName,
      stripePublishableKey: stripePublishableKey,
      security: _security,
    );
    _gateways[PaymentMethod.applePay] = walletGateway;
    _gateways[PaymentMethod.googlePay] = walletGateway;

    _initialized = true;
  }

  void _ensureInitialized() {
    if (!_initialized) {
      throw StateError('PaymentService not initialized. Call initialize() first.');
    }
  }

  Future<PaymentResult> processPayment(PaymentRequest request) async {
    _ensureInitialized();

    // Input validation
    final validationError = _validateRequest(request);
    if (validationError != null) {
      return PaymentResult(
        transactionId: _security.generateTransactionId(),
        status: PaymentStatus.failed,
        amount: request.amount,
        errorMessage: validationError,
        processedAt: DateTime.now().toUtc(),
      );
    }

    // Fraud check
    final fraudCheck = _fraudDetector.checkTransaction(
      amount: request.amount.amount,
      currency: request.amount.currency,
    );

    if (!fraudCheck.isAllowed) {
      await _logger.logTransaction(
        transactionId: _security.generateTransactionId(),
        status: PaymentStatus.failed,
        amount: request.amount,
        method: request.method,
        errorMessage: 'Fraud check failed: ${fraudCheck.reason}',
        metadata: {'risk_score': fraudCheck.riskScore},
      );

      return PaymentResult(
        transactionId: _security.generateTransactionId(),
        status: PaymentStatus.failed,
        amount: request.amount,
        errorMessage: 'Transaction declined for security reasons',
        errorCode: 'FRAUD_CHECK_FAILED',
        processedAt: DateTime.now().toUtc(),
      );
    }

    // Get appropriate gateway
    final gateway = _gateways[request.method];
    if (gateway == null) {
      return PaymentResult(
        transactionId: _security.generateTransactionId(),
        status: PaymentStatus.failed,
        amount: request.amount,
        errorMessage: 'Payment method not supported',
        processedAt: DateTime.now().toUtc(),
      );
    }

    // Check gateway availability
    final available = await gateway.isAvailable();
    if (!available) {
      return PaymentResult(
        transactionId: _security.generateTransactionId(),
        status: PaymentStatus.failed,
        amount: request.amount,
        errorMessage: 'Payment gateway temporarily unavailable',
        processedAt: DateTime.now().toUtc(),
      );
    }

    // Process payment with retry logic
    PaymentResult result;
    try {
      result = await _processWithRetry(gateway, request, maxRetries: 2);
    } catch (e) {
      result = PaymentResult(
        transactionId: _security.generateTransactionId(),
        status: PaymentStatus.failed,
        amount: request.amount,
        errorMessage: 'Unexpected payment error',
        processedAt: DateTime.now().toUtc(),
      );
    }

    // Record transaction for fraud detection
    if (result.isSuccessful) {
      _fraudDetector.recordTransaction(request.amount.amount);
    }

    // Log transaction
    await _logger.logTransaction(
      transactionId: result.transactionId,
      status: result.status,
      amount: request.amount,
      method: request.method,
      errorMessage: result.errorMessage,
      metadata: {
        'risk_score': fraudCheck.riskScore,
        'idempotency_key': request.idempotencyKey,
      },
    );

    return result;
  }

  Future<PaymentResult> _processWithRetry(
    PaymentGateway gateway,
    PaymentRequest request, {
    int maxRetries = 2,
  }) async {
    PaymentResult? lastResult;

    for (int attempt = 0; attempt <= maxRetries; attempt++) {
      try {
        lastResult = await gateway.processPayment(request);

        if (lastResult.isSuccessful ||
            lastResult.status == PaymentStatus.cancelled ||
            lastResult.errorCode == 'FRAUD_CHECK_FAILED') {
          return lastResult;
        }

        // Only retry on network/transient errors
        if (lastResult.errorCode != 'NETWORK_ERROR' &&
            lastResult.errorCode != 'TIMEOUT') {
          return lastResult;
        }

        if (attempt < maxRetries) {
          await Future.delayed(Duration(seconds: (attempt + 1) * 2));
        }
      } catch (e) {
        if (attempt == maxRetries) rethrow;
        await Future.delayed(Duration(seconds: (attempt + 1) * 2));
      }
    }

    return lastResult ??
        PaymentResult(
          transactionId: _security.generateTransactionId(),
          status: PaymentStatus.failed,
          amount: request.amount,
          errorMessage: 'Payment failed after retries',
          processedAt: DateTime.now().toUtc(),
        );
  }

  Future<PaymentResult> refundPayment({
    required String transactionId,
    required PaymentAmount amount,
    required PaymentMethod method,
  }) async {
    _ensureInitialized();

    final gateway = _gateways[method];
    if (gateway == null) {
      return PaymentResult(
        transactionId: transactionId,
        status: PaymentStatus.failed,
        amount: amount,
        errorMessage: 'Payment method not supported for refunds',
        processedAt: DateTime.now().toUtc(),
      );
    }

    final result = await gateway.refundPayment(transactionId, amount);

    await _logger.logTransaction(
      transactionId: result.transactionId,
      status: result.status,
      amount: amount,
      method: method,
      errorMessage: result.errorMessage,
      metadata: {'original_transaction': transactionId, 'type': 'refund'},
    );

    return result;
  }

  Future<PaymentResult> verifyPayment({
    required String transactionId,
    required PaymentMethod method,
  }) async {
    _ensureInitialized();

    final gateway = _gateways[method];
    if (gateway == null) {
      return PaymentResult(
        transactionId: transactionId,
        status: PaymentStatus.failed,
        amount: const PaymentAmount(amount: 0),
        errorMessage: 'Payment method not supported',
        processedAt: DateTime.now().toUtc(),
      );
    }

    return gateway.verifyPayment(transactionId);
  }

  Future<Map<PaymentMethod, bool>> getAvailablePaymentMethods() async {
    _ensureInitialized();

    final results = <PaymentMethod, bool>{};
    for (final entry in _gateways.entries) {
      try {
        results[entry.key] = await entry.value.isAvailable();
      } catch (_) {
        results[entry.key] = false;
      }
    }
    return results;
  }

  String? _validateRequest(PaymentRequest request) {
    if (request.amount.amount <= 0) {
      return 'Payment amount must be greater than zero';
    }
    if (request.amount.amount > 999999.99) {
      return 'Payment amount exceeds maximum limit';
    }
    if (request.amount.currency.isEmpty) {
      return 'Currency is required';
    }
    if (request.amount.currency.length != 3) {
      return 'Invalid currency code';
    }
    if (request.method == PaymentMethod.creditCard ||
        request.method == PaymentMethod.debitCard) {
      if (request.tokenizedCard == null || request.tokenizedCard!.isEmpty) {
        return 'Tokenized card data is required';
      }
    }
    if (request.method == PaymentMethod.inAppPurchase) {
      if (request.productId == null || request.productId!.isEmpty) {
        return 'Product ID is required for in-app purchases';
      }
    }
    return null;
  }

  PaymentRequest createPaymentRequest({
    required PaymentAmount amount,
    required PaymentMethod method,
    TransactionType type = TransactionType.purchase,
    String? tokenizedCard,
    String? productId,
    Map<String, dynamic>? metadata,
  }) {
    return PaymentRequest(
      idempotencyKey: _security.generateIdempotencyKey(),
      amount: amount,
      method: method,
      type: type,
      tokenizedCard: tokenizedCard,
      productId: productId,
      metadata: metadata,
    );
  }

  String tokenizeCard(String cardNumber) {
    return _security.tokenizeCardNumber(cardNumber);
  }

  String maskCard(String cardNumber) {
    return _security.maskCardNumber(cardNumber);
  }

  void dispose() {
    for (final gateway in _gateways.values) {
      if (gateway is InAppPurchaseGateway) {
        gateway.dispose();
      }
    }
    _gateways.clear();
    _initialized = false;
  }
}

