import 'dart:convert';
import 'package:flutter/foundation.dart';
import '../models/payment_models.dart';

class TransactionLogger {
  final List<TransactionLog> _logs = [];

  Future<void> logTransaction({
    required String transactionId,
    required PaymentStatus status,
    required PaymentAmount amount,
    required PaymentMethod method,
    String? errorMessage,
    Map<String, dynamic>? metadata,
  }) async {
    final log = TransactionLog(
      transactionId: transactionId,
      status: status,
      amount: amount,
      method: method,
      errorMessage: errorMessage,
      metadata: metadata,
      timestamp: DateTime.now().toUtc(),
    );

    _logs.add(log);

    // In production, send to secure logging service
    // Never log sensitive card data
    if (kDebugMode) {
      debugPrint(
        '[PAYMENT] ${log.timestamp.toIso8601String()} '
        '${log.transactionId} ${log.status.name} '
        '${log.amount.currency} ${log.amount.amount} '
        '${log.method.name} '
        '${log.errorMessage ?? ""}',
      );
    }
  }

  List<TransactionLog> getRecentLogs({int limit = 50}) {
    final sorted = List<TransactionLog>.from(_logs)
      ..sort((a, b) => b.timestamp.compareTo(a.timestamp));
    return sorted.take(limit).toList();
  }

  void clearLogs() => _logs.clear();
}

class TransactionLog {
  final String transactionId;
  final PaymentStatus status;
  final PaymentAmount amount;
  final PaymentMethod method;
  final String? errorMessage;
  final Map<String, dynamic>? metadata;
  final DateTime timestamp;

  const TransactionLog({
    required this.transactionId,
    required this.status,
    required this.amount,
    required this.method,
    this.errorMessage,
    this.metadata,
    required this.timestamp,
  });

  Map<String, dynamic> toJson() => {
    'transaction_id': transactionId,
    'status': status.name,
    'amount': amount.toJson(),
    'method': method.name,
    'error_message': errorMessage,
    'metadata': metadata,
    'timestamp': timestamp.toIso8601String(),
  };
}

