import 'package:flutter/material.dart';
import '../models/payment_models.dart';
import '../services/payment_service.dart';

class PaymentSheet extends StatefulWidget {
  final PaymentAmount amount;
  final PaymentService paymentService;
  final String? productId;
  final void Function(PaymentResult result) onPaymentComplete;
  final VoidCallback? onCancel;

  const PaymentSheet({
    super.key,
    required this.amount,
    required this.paymentService,
    this.productId,
    required this.onPaymentComplete,
    this.onCancel,
  });

  @override
  State<PaymentSheet> createState() => _PaymentSheetState();
}

class _PaymentSheetState extends State<PaymentSheet> {
  bool _isProcessing = false;
  Map<PaymentMethod, bool> _availableMethods = {};
  PaymentMethod? _selectedMethod;
  String? _errorMessage;

  final _cardNumberController = TextEditingController();
  final _expiryController = TextEditingController();
  final _cvvController = TextEditingController();
  final _formKey = GlobalKey<FormState>();

  @override
  void initState() {
    super.initState();
    _loadAvailableMethods();
  }

  @override
  void dispose() {
    _cardNumberController.dispose();
    _expiryController.dispose();
    _cvvController.dispose();
    super.dispose();
  }

  Future<void> _loadAvailableMethods() async {
    final methods = await widget.paymentService.getAvailablePaymentMethods();
    if (mounted) {
      setState(() {
        _availableMethods = methods;
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Container(
      padding: const EdgeInsets.all(24),
      decoration: BoxDecoration(
        color: Theme.of(context).scaffoldBackgroundColor,
        borderRadius: const BorderRadius.vertical(top: Radius.circular(20)),
      ),
      child: SafeArea(
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            _buildHeader(context),
            const SizedBox(height: 24),
            _buildAmountDisplay(),
            const SizedBox(height: 24),
            _buildPaymentMethodSelector(),
            if (_selectedMethod == PaymentMethod.creditCard ||
                _selectedMethod == PaymentMethod.debitCard) ...[
              const SizedBox(height: 16),
              _buildCardForm(),
            ],
            if (_errorMessage != null) ...[
              const SizedBox(height: 12),
              _buildErrorMessage(),
            ],
            const SizedBox(height: 24),
            _buildPayButton(),
            const SizedBox(height: 12),
            _buildCancelButton(),
          ],
        ),
      ),
    );
  }

  Widget _buildHeader(BuildContext context) {
    return Row(
      mainAxisAlignment: MainAxisAlignment.spaceBetween,
      children: [
        Text(
          'Payment',
          style: Theme.of(context).textTheme.headlineSmall?.copyWith(
            fontWeight: FontWeight.bold,
          ),
        ),
        const Icon(Icons.lock, color: Colors.green, size: 20),
      ],
    );
  }

  Widget _buildAmountDisplay() {
    return Container(
      padding: const EdgeInsets.all(16),
      decoration: BoxDecoration(
        color: Colors.grey.shade100,
        borderRadius: BorderRadius.circular(12),
      ),
      child: Row(
        mainAxisAlignment: MainAxisAlignment.spaceBetween,
        children: [
          const Text('Total', style: TextStyle(fontSize: 16)),
          Text(
            '${widget.amount.currency} ${widget.amount.amount.toStringAsFixed(2)}',
            style: const TextStyle(
              fontSize: 24,
              fontWeight: FontWeight.bold,
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildPaymentMethodSelector() {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        const Text(
          'Payment Method',
          style: TextStyle(fontSize: 14, fontWeight: FontWeight.w600),
        ),
        const SizedBox(height: 8),
        Wrap(
          spacing: 8,
          runSpacing: 8,
          children: [
            if (_availableMethods[PaymentMethod.creditCard] == true)
              _buildMethodChip(PaymentMethod.creditCard, 'Credit Card', Icons.credit_card),
            if (_availableMethods[PaymentMethod.applePay] == true)
              _buildMethodChip(PaymentMethod.applePay, 'Apple Pay', Icons.apple),
            if (_availableMethods[PaymentMethod.googlePay] == true)
              _buildMethodChip(PaymentMethod.googlePay, 'Google Pay', Icons.g_mobiledata),
            if (_availableMethods[PaymentMethod.inAppPurchase] == true &&
                widget.productId != null)
              _buildMethodChip(
                PaymentMethod.inAppPurchase,
                'In-App Purchase',
                Icons.shopping_bag,
              ),
          ],
        ),
      ],
    );
  }

  Widget _buildMethodChip(PaymentMethod method, String label, IconData icon) {
    final isSelected = _selectedMethod == method;
    return ChoiceChip(
      label: Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          Icon(icon, size: 18),
          const SizedBox(width: 4),
          Text(label),
        ],
      ),
      selected: isSelected,
      onSelected: _isProcessing
          ? null
          : (selected) {
              setState(() {
                _selectedMethod = selected ? method : null;
                _errorMessage = null;
              });
            },
    );
  }

  Widget _buildCardForm() {
    return Form(
      key: _formKey,
      child: Column(
        children: [
          TextFormField(
            controller: _cardNumberController,
            decoration: const InputDecoration(
              labelText: 'Card Number',
              hintText: '4242 4242 4242 4242',
              border: OutlineInputBorder(),
              prefixIcon: Icon(Icons.credit_card),
            ),
            keyboardType: TextInputType.number,
            maxLength: 19,
            enabled: !_isProcessing,
            validator: (value) {
              if (value == null || value.replaceAll(' ', '').length < 13) {
                return 'Enter a valid card number';
              }
              return null;
            },
            onChanged: (value) {
              // Auto-format card number with spaces
              final cleaned = value.replaceAll(' ', '');
              if (cleaned.length > 16) return;
              final formatted = cleaned.replaceAllMapped(
                RegExp(r'.{4}'),
                (match) => '${match.group(0)} ',
              ).trim();
              if (formatted != value) {
                _cardNumberController.value = TextEditingValue(
                  text: formatted,
                  selection: TextSelection.collapsed(offset: formatted.length),
                );
              }
            },
          ),
          const SizedBox(height: 12),
          Row(
            children: [
              Expanded(
                child: TextFormField(
                  controller: _expiryController,
                  decoration: const InputDecoration(
                    labelText: 'MM/YY',
                    border: OutlineInputBorder(),
                  ),
                  keyboardType: TextInputType.number,
                  maxLength: 5,
                  enabled: !_isProcessing,
                  validator: (value) {
                    if (value == null || !RegExp(r'^\d{2}/\d{2}$').hasMatch(value)) {
                      return 'Invalid expiry';
                    }
                    final parts = value.split('/');
                    final month = int.tryParse(parts[0]);
                    if (month == null || month < 1 || month > 12) {
                      return 'Invalid month';
                    }
                    return null;
                  },
                  onChanged: (value) {
                    if (value.length == 2 && !value.contains('/')) {
                      _expiryController.text = '$value/';
                      _expiryController.selection = TextSelection.collapsed(
                        offset: _expiryController.text.length,
                      );
                    }
                  },
                ),
              ),
              const SizedBox(width: 12),
              Expanded(
                child: TextFormField(
                  controller: _cvvController,
                  decoration: const InputDecoration(
                    labelText: 'CVV',
                    border: OutlineInputBorder(),
                  ),
                  keyboardType: TextInputType.number,
                  maxLength: 4,
                  obscureText: true,
                  enabled: !_isProcessing,
                  validator: (value) {
                    if (value == null || value.length < 3) {
                      return 'Invalid CVV';
                    }
                    return null;
                  },
                ),
              ),
            ],
          ),
        ],
      ),
    );
  }

